            .stdout(std::process::Stdio::null())
            .stderr(std::process::Stdio::null())
            .status()
            .unwrap();
        std::fs::write(dir.path().join(".gitignore"), "*.gen.rs\n").unwrap();
        let ignored = dir.path().join("foo.gen.rs");
