88	pub fn jaccard(a: &[u64], b: &[u64]) -> f64 {
89	    if a.is_empty() && b.is_empty() {
90	        return 1.0;
91	    }
92	    let set_a: HashSet<u64> = a.iter().copied().collect();
93	    let set_b: HashSet<u64> = b.iter().copied().collect();
94	    let intersection = set_a.intersection(&set_b).count();
95	    let union = set_a.union(&set_b).count();
96	    if union == 0 {
97	        return 0.0;
98	    }
99	    intersection as f64 / union as f64
100	}
