129	pub fn find_duplicate_pairs(
130	    functions: &[FunctionInfo],
131	    threshold: f64,
132	    min_lines: usize,
133	    min_nodes: usize,
134	) -> Vec<DuplicatePair> {
135	    let candidates: Vec<&FunctionInfo> = functions
136	        .iter()
137	        .filter(|f| source_lines(f) >= min_lines && f.node_hashes.len() >= min_nodes)
138	        .collect();
139	
140	    let mut pairs: Vec<DuplicatePair> = Vec::new();
141	
142	    for i in 0..candidates.len() {
143	        for j in (i + 1)..candidates.len() {
144	            let a = candidates[i];
145	            let b = candidates[j];
146	            if is_same_location(a, b) {
147	                continue;
148	            }
149	            let score = jaccard(&a.node_hashes, &b.node_hashes);
150	            if score >= threshold {
151	                pairs.push(make_pair(a, b, score));
152	            }
153	        }
154	    }
155	
156	    pairs.sort_by(|a, b| {
157	        b.score
158	            .partial_cmp(&a.score)
159	            .unwrap_or(std::cmp::Ordering::Equal)
160	            .then_with(|| a.left.file.cmp(&b.left.file))
161	            .then_with(|| a.left.start_line.cmp(&b.left.start_line))
162	            .then_with(|| a.right.file.cmp(&b.right.file))
163	            .then_with(|| a.right.start_line.cmp(&b.right.start_line))
164	    });
165	
166	    pairs
167	}
168	
169	fn order_endpoints<'a>(
170	    a: &'a FunctionInfo,
171	    b: &'a FunctionInfo,
172	) -> (&'a FunctionInfo, &'a FunctionInfo) {
173	    let cmp = a
174	        .file
175	        .cmp(&b.file)
176	        .then_with(|| a.start_line.cmp(&b.start_line));
177	    if cmp == std::cmp::Ordering::Greater {
178	        (b, a)
179	    } else {
180	        (a, b)
181	    }
182	}
