249	pub fn execute_cli(
250	    paths: &[String],
251	    format_str: &str,
252	    lang: Option<&str>,
253	    config: Config,
254	    run_fn: impl Fn(&[String], &Config) -> RunResult,
255	) -> CliResult {
256	    let format = match parse_output_format(format_str) {
257	        Ok(f) => f,
258	        Err(e) => return cli_error(e),
259	    };
260	
261	    let lang_val = if let Some(lang) = lang {
262	        match validate_lang(lang) {
263	            Ok(l) => Some(l),
264	            Err(e) => return cli_error(e),
265	        }
266	    } else {
267	        None
268	    };
269	
270	    let config = Config {
271	        format,
272	        lang: lang_val,
273	        ..config
274	    };
275	    let result = run_fn(paths, &config);
276	    run_result_to_cli(result, &config.format)
277	}
