168	fn extract_rust_let_declaration(
169	    node: tree_sitter::Node,
170	    source: &str,
171	    file: &str,
172	    functions: &mut Vec<FunctionInfo>,
173	) {
174	    if let Some(val) = find_child_by_field(node, "value")
175	        && val.kind() == "closure_expression"
176	    {
177	        functions.push(make_function_info(node, source, file, &RUST_CONFIG));
178	    }
179	    for child in children_of(node) {
180	        if child.kind() != "closure_expression" {
181	            extract_rust_functions(child, source, file, functions);
182	        }
183	    }
184	}
