186	fn extract_jsts_export_statement(
187	    node: tree_sitter::Node,
188	    source: &str,
189	    file: &str,
190	    config: &LangConfig,
191	    functions: &mut Vec<FunctionInfo>,
192	) {
193	    let fn_decls: Vec<_> = children_of(node)
194	        .into_iter()
195	        .filter(|c| c.kind() == "function_declaration")
196	        .collect();
197	    if fn_decls.is_empty() {
198	        for child in children_of(node) {
199	            extract_jsts_functions(child, source, file, config, functions);
200	        }
201	    } else {
202	        for child in fn_decls {
203	            functions.push(make_function_info(child, source, file, config));
204	        }
205	    }
206	}
