208	fn extract_jsts_lexical_declaration(
209	    node: tree_sitter::Node,
210	    source: &str,
211	    file: &str,
212	    config: &LangConfig,
213	    functions: &mut Vec<FunctionInfo>,
214	) {
215	    for child in children_of(node) {
216	        if child.kind() == "variable_declarator" {
217	            extract_jsts_variable_declarator(child, source, file, config, functions);
218	        }
219	    }
220	}
