222	fn extract_jsts_class_body(
223	    node: tree_sitter::Node,
224	    source: &str,
225	    file: &str,
226	    config: &LangConfig,
227	    functions: &mut Vec<FunctionInfo>,
228	) {
229	    for child in children_of(node) {
230	        if child.kind() == "method_definition" {
231	            functions.push(make_function_info(child, source, file, config));
232	        }
233	    }
