236	fn try_extract_jsts_node(
237	    node: tree_sitter::Node,
238	    source: &str,
239	    file: &str,
240	    config: &LangConfig,
241	    functions: &mut Vec<FunctionInfo>,
242	) -> bool {
243	    match node.kind() {
244	        "function_declaration" => functions.push(make_function_info(node, source, file, config)),
245	        "export_statement" => extract_jsts_export_statement(node, source, file, config, functions),
246	        "lexical_declaration" => {
247	            extract_jsts_lexical_declaration(node, source, file, config, functions)
248	        }
249	        "class_body" => extract_jsts_class_body(node, source, file, config, functions),
250	        _ => return false,
251	    }
252	    true
253	}
