255	fn extract_jsts_functions(
256	    node: tree_sitter::Node,
257	    source: &str,
258	    file: &str,
259	    config: &LangConfig,
260	    functions: &mut Vec<FunctionInfo>,
261	) {
262	    if !try_extract_jsts_node(node, source, file, config, functions) {
263	        for child in children_of(node) {
264	            extract_jsts_functions(child, source, file, config, functions);
265	        }
266	    }
