270	    node: tree_sitter::Node,
271	    source: &str,
272	    file: &str,
273	    config: &LangConfig,
274	    functions: &mut Vec<FunctionInfo>,
275	) {
276	    if let Some(val) = find_child_by_field(node, "value")
277	        && val.kind() == "arrow_function"
278	    {
