283	pub fn find_child_by_field<'a>(
284	    node: tree_sitter::Node<'a>,
285	    field: &str,
286	) -> Option<tree_sitter::Node<'a>> {
287	    let mut cursor = node.walk();
288	    for child in node.children(&mut cursor) {
289	        if child.kind() == field {
290	            return Some(child);
291	        }
292	    }
293	    node.child_by_field_name(field)
294	}
295	
296	pub fn make_function_info(
297	    node: tree_sitter::Node,
298	    source: &str,
299	    file: &str,
300	    config: &LangConfig,
301	) -> FunctionInfo {
302	    let start_line = node.start_position().row + 1;
303	    let end_line = node.end_position().row + 1;
304	    let hashes = collect_subtree_hashes(node, source, config);
305	    FunctionInfo {
306	        file: file.to_string(),
307	        start_line,
308	        end_line,
309	        node_hashes: hashes,
310	    }
311	}
312	
313	fn normalize_node_text(node: tree_sitter::Node, source: &str, config: &LangConfig) -> String {
314	    let kind = node.kind();
315	    if config.identifier_kinds.contains(&kind) {
316	        return "_ID".to_string();
317	    }
318	    if config.literal_kinds.contains(&kind) {
319	        return "_LIT".to_string();
320	    }
321	    let start = node.start_byte();
322	    let end = node.end_byte();
323	    source[start..end].to_string()
324	}
325	
326	pub fn build_normalized_subtree(
327	    node: tree_sitter::Node,
328	    source: &str,
329	    config: &LangConfig,
330	) -> String {
331	    if node.child_count() == 0 {
332	        return normalize_node_text(node, source, config);
333	    }
334	    let mut parts = vec![format!("({}:", node.kind())];
335	    let mut cursor = node.walk();
336	    for child in node.children(&mut cursor) {
337	        parts.push(build_normalized_subtree(child, source, config));
338	    }
339	    parts.push(")".to_string());
340	    parts.join("")
341	}
342	
343	fn hash_str(s: &str) -> u64 {
344	    use std::hash::{Hash, Hasher};
345	    let mut h = std::collections::hash_map::DefaultHasher::new();
346	    s.hash(&mut h);
347	    h.finish()
348	}
349	
350	fn collect_subtree_hashes(node: tree_sitter::Node, source: &str, config: &LangConfig) -> Vec<u64> {
351	    let mut hashes = Vec::new();
352	    collect_hashes_recursive(node, source, config, &mut hashes);
353	    hashes.sort_unstable();
354	    hashes
355	}
356	
357	fn collect_hashes_recursive(
358	    node: tree_sitter::Node,
359	    source: &str,
360	    config: &LangConfig,
361	    hashes: &mut Vec<u64>,
362	) {
363	    let subtree = build_normalized_subtree(node, source, config);
364	    hashes.push(hash_str(&subtree));
365	    let mut cursor = node.walk();
366	    for child in node.children(&mut cursor) {
367	        collect_hashes_recursive(child, source, config, hashes);
368	    }
369	}
