        (parts[0].trim(), parts[1].trim(), parts[2].trim())
    } else {
        ("a", "b", "sum")
    };
    format!(
        "def {fn_name}({p0}, {p1}):\n    {p2} = {p0} + {p1}\n    extra = {p2} * 2\n    more = extra + {p0}\n    result = more + {p1}\n    return result\n"
    )
}

